+	switch permission {
+	case "admin":
+		for _, r := range s.adminRoles {
+			if u.Role == r {
+				return true, nil
+			}
+		}
+		return false, nil
+	case "owner":
+		return userID == targetUserID, nil
+	case "admin_or_owner":
+		if userID == targetUserID {
