*** Add File: store/store.go
+package store
+
+import (
+	"errors"
+	"fmt"
+	"strings"
+	"sync"
+	"time"
+
+	"refactor/types"
+)
+
+// Store holds internal state and business logic.
+type Store struct {
+	mu            sync.RWMutex
+	users         map[string]*types.User
+	orders        map[string]*types.Order
+	notifications []types.Notification
+	userCounter   int
+	orderCounter  int
+	emailDomain   string
+	maxItems      int
+	adminRoles    []string
+}
+
+func NewStore() *Store {
+	return &Store{
+		users:         make(map[string]*types.User),
+		orders:        make(map[string]*types.Order),
+		notifications: make([]types.Notification, 0),
+		emailDomain:   "",
+		maxItems:      100,
+		adminRoles:    []string{"admin", "superadmin"},
+	}
+}
+
+// ---------- User Management ----------
+func (s *Store) CreateUser(email, name, role string) (*types.User, error) {
+	s.mu.Lock()
+	defer s.mu.Unlock()
+	if email == "" {
+		return nil, errors.New("email is required")
+	}
+	if !strings.Contains(email, "@") {
+		return nil, errors.New("email must contain @")
+	}
+	parts := strings.Split(email, "@")
+	if len(parts) != 2 || parts[0] == "" || parts[1] == "" {
+		return nil, errors.New("email format is invalid")
+	}
+	if !strings.Contains(parts[1], ".") {
+		return nil, errors.New("email domain must contain a dot")
+	}
+	if s.emailDomain != "" && parts[1] != s.emailDomain {
+		return nil, fmt.Errorf("email must be from domain %s", s.emailDomain)
+	}
+	for _, u := range s.users {
+		if u.Email == email {
+			return nil, errors.New("email already registered")
+		}
+	}
+	if role == "" {
+		role = "user"
+	}
+	s.userCounter++
+	user := &types.User{
+		ID:       fmt.Sprintf("user-%d", s.userCounter),
+		Email:    email,
+		Name:     name,
+		Role:     role,
+		Verified: false,
+	}
+	s.users[user.ID] = user
+	subject := fmt.Sprintf("Welcome to our platform, %s!", name)
+	body := fmt.Sprintf("Hi %s,\n\nYour account has been created with email %s.\nPlease verify your email to get started.\n\nBest regards,\nThe Team", name, email)
+	s.notifications = append(s.notifications, types.Notification{To: email, Subject: subject, Body: body})
+	return user, nil
+}
+
+func (s *Store) GetUser(id string) (*types.User, error) {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	u, ok := s.users[id]
+	if !ok {
+		return nil, fmt.Errorf("user %s not found", id)
+	}
+	return u, nil
+}
+
+func (s *Store) UpdateUser(id, name, role string) (*types.User, error) {
+	s.mu.Lock()
+	defer s.mu.Unlock()
+	u, ok := s.users[id]
+	if !ok {
+		return nil, fmt.Errorf("user %s not found", id)
+	}
+	if name != "" {
+		u.Name = name
+	}
+	if role != "" {
+		u.Role = role
+	}
+	return u, nil
+}
+
+func (s *Store) DeleteUser(id string) error {
+	s.mu.Lock()
+	defer s.mu.Unlock()
+	if _, ok := s.users[id]; !ok {
+		return fmt.Errorf("user %s not found", id)
+	}
+	for _, o := range s.orders {
+		if o.UserID == id && o.Status == "active" {
+			return fmt.Errorf("cannot delete user %s: has active orders", id)
+		}
+	}
+	delete(s.users, id)
+	return nil
+}
+
+func (s *Store) VerifyEmail(userID string) error {
+	s.mu.Lock()
+	defer s.mu.Unlock()
+	u, ok := s.users[userID]
+	if !ok {
+		return fmt.Errorf("user %s not found", userID)
+	}
+	u.Verified = true
+	return nil
+}
+
+// ---------- Order Management ----------
+func (s *Store) CreateOrder(userID string, items []types.OrderItem) (*types.Order, error) {
+	s.mu.Lock()
+	defer s.mu.Unlock()
+	user, ok := s.users[userID]
+	if !ok {
+		return nil, fmt.Errorf("user %s not found", userID)
+	}
+	if err := s.ValidateOrder(items); err != nil {
+		return nil, err
+	}
+	var total float64
+	for _, it := range items {
+		total += it.Price * float64(it.Quantity)
+	}
+	s.orderCounter++
+	order := &types.Order{
+		ID:        fmt.Sprintf("order-%d", s.orderCounter),
+		UserID:    userID,
+		Items:     items,
+		Status:    "active",
+		Total:     total,
+		CreatedAt: time.Now().Format(time.RFC3339),
+	}
+	s.orders[order.ID] = order
+	// notification
+	itemLines := ""
+	for _, it := range items {
+		itemLines += fmt.Sprintf("  - %s (x%d): $%.2f\n", it.Name, it.Quantity, it.Price*float64(it.Quantity))
+	}
+	subject := fmt.Sprintf("Order %s confirmed", order.ID)
+	body := fmt.Sprintf("Hi %s,\n\nYour order %s has been confirmed.\n\nItems:\n%s\nTotal: $%.2f\n\nThank you for your purchase!", user.Name, order.ID, itemLines, total)
+	s.notifications = append(s.notifications, types.Notification{To: user.Email, Subject: subject, Body: body})
+	return order, nil
+}
+
+func (s *Store) GetOrder(id string) (*types.Order, error) {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	o, ok := s.orders[id]
+	if !ok {
+		return nil, fmt.Errorf("order %s not found", id)
+	}
+	return o, nil
+}
+
+func (s *Store) ListOrdersByUser(userID string) ([]*types.Order, error) {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	if _, ok := s.users[userID]; !ok {
+		return nil, fmt.Errorf("user %s not found", userID)
+	}
+	var res []*types.Order
+	for _, o := range s.orders {
+		if o.UserID == userID {
+			res = append(res, o)
+		}
+	}
+	return res, nil
+}
+
+func (s *Store) CancelOrder(orderID, cancelledByUserID string) error {
+	s.mu.Lock()
+	defer s.mu.Unlock()
+	order, ok := s.orders[orderID]
+	if !ok {
+		return fmt.Errorf("order %s not found", orderID)
+	}
+	if order.Status == "cancelled" {
+		return errors.New("order is already cancelled")
+	}
+	user, ok := s.users[cancelledByUserID]
+	if !ok {
+		return fmt.Errorf("user %s not found", cancelledByUserID)
+	}
+	isAdmin := false
+	for _, r := range s.adminRoles {
+		if user.Role == r {
+			isAdmin = true
+			break
+		}
+	}
+	if !isAdmin && order.UserID != cancelledByUserID {
+		return errors.New("permission denied: only order owner or admin can cancel")
+	}
+	order.Status = "cancelled"
+	owner, exists := s.users[order.UserID]
+	if exists {
+		subj := fmt.Sprintf("Order %s cancelled", orderID)
+		body := fmt.Sprintf("Hi %s,\n\nYour order %s has been cancelled.\n\nIf you did not request this, please contact support.\n\nBest regards,\nThe Team", owner.Name, orderID)
+		s.notifications = append(s.notifications, types.Notification{To: owner.Email, Subject: subj, Body: body})
+	}
+	return nil
+}
+
+func (s *Store) CalculateTotal(items []types.OrderItem) float64 {
+	var total float64
+	for _, it := range items {
+		total += it.Price * float64(it.Quantity)
+	}
+	return total
+}
+
+func (s *Store) GetNotifications() []types.Notification {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	out := make([]types.Notification, len(s.notifications))
+	copy(out, s.notifications)
+	return out
+}
+
+// ---------- Validation ----------
+func (s *Store) ValidateEmail(email string) error {
+	if email == "" {
+		return errors.New("email is required")
+	}
+	if !strings.Contains(email, "@") {
+		return errors.New("email must contain @")
+	}
+	parts := strings.Split(email, "@")
+	if len(parts) != 2 || parts[0] == "" || parts[1] == "" {
+		return errors.New("email format is invalid")
+	}
+	if !strings.Contains(parts[1], ".") {
+		return errors.New("email domain must contain a dot")
+	}
+	if s.emailDomain != "" && parts[1] != s.emailDomain {
+		return fmt.Errorf("email must be from domain %s", s.emailDomain)
+	}
+	return nil
+}
+
+func (s *Store) ValidateOrder(items []types.OrderItem) error {
+	if len(items) == 0 {
+		return errors.New("order must have at least one item")
+	}
+	if len(items) > s.maxItems {
+		return fmt.Errorf("order cannot exceed %d items", s.maxItems)
+	}
+	for i, it := range items {
+		if it.ProductID == "" {
+			return fmt.Errorf("item %d: product ID is required", i)
+		}
+		if it.Price < 0 {
+			return fmt.Errorf("item %d: price cannot be negative", i)
+		}
+		if it.Quantity <= 0 {
+			return fmt.Errorf("item %d: quantity must be positive", i)
+		}
+	}
+	return nil
+}
+
+func (s *Store) CheckUserPermission(userID, targetUserID, permission string) (bool, error) {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	u, ok := s.users[userID]
+	if !ok {
+		return false, fmt.Errorf("user %s not found", userID)
+	}
+	switch permission {
+	case "admin":
+		for _, r := range s.adminRoles {
+			if u.Role == r {
+				return true, nil
+			}
+		}
+		return false, nil
+	case "owner":
+		return userID == targetUserID, nil
+	case "admin_or_owner":
+		if userID == targetUserID {
+			return true, nil
+		}
+		for _, r := range s.adminRoles {
+			if u.Role == r {
+				return true, nil
+			}
+		}
+		return false, nil
+	}
+	return false, fmt.Errorf("unknown permission %s", permission)
+}
